// ============================================================================
// CONTENT CARD COMPONENT
// ============================================================================
// Displays a single content item with edit/delete buttons

import React from 'react';
import { ContentItem } from '../types/content.types';

interface ContentCardProps {
  content: ContentItem;
  onEdit: (content: ContentItem) => void;
  onDelete: (contentId: number) => void;
}

export const ContentCard: React.FC<ContentCardProps> = ({
  content,
  onEdit,
  onDelete,
}) => {
  console.log('[ContentCard] Rendering with content:', content);

  return (
    <div
      style={{
        background: '#fff',
        borderRadius: '8px',
        padding: '16px',
        marginBottom: '12px',
        boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
        display: 'flex',
        gap: '12px',
        alignItems: 'flex-start',
        minHeight: '100px',
        border: '1px solid #e5e7eb',
      }}
    >
      {/* Icon */}
      <div
        style={{
          fontSize: '32px',
          minWidth: '50px',
          textAlign: 'center',
        }}
      >
        {content.type === 'video' && ''}
        {content.type === 'audio' && ''}
        {content.type === 'activity' && ''}
      </div>

      {/* Content Info */}
      <div style={{ flex: 1 }}>
        <h3 style={{ margin: '0 0 8px', color: '#1e3a5f' }}>
          {content.title}
        </h3>
        <p style={{ margin: '0 0 8px', fontSize: '14px', color: '#64748b' }}>
          {content.description}
        </p>
        <div style={{ display: 'flex', gap: '16px', fontSize: '12px', color: '#94a3b8' }}>
          <span> Type: {content.type}</span>
          {(content as any).category && <span>️ {(content as any).category}</span>}
          {(content as any).duration && <span>⏱️ {(content as any).duration}</span>}
          {(content as any).steps && <span> {(content as any).steps} steps</span>}
          {(content as any).minutes && <span>⏰ {(content as any).minutes} min</span>}
        </div>
      </div>

      {/* Action Buttons */}
      <div style={{ display: 'flex', gap: '8px', flexShrink: 0, minWidth: '200px' }}>
        <button
          onClick={() => {
            console.log('[ContentCard] Edit clicked for content:', content.id);
            onEdit(content);
          }}
          style={{
            padding: '10px 16px',
            background: '#3b82f6',
            color: '#fff',
            border: 'none',
            borderRadius: '6px',
            cursor: 'pointer',
            fontSize: '14px',
            fontWeight: 'bold',
            transition: 'background 0.3s',
            whiteSpace: 'nowrap',
          }}
          onMouseEnter={(e) => (e.currentTarget.style.background = '#2563eb')}
          onMouseLeave={(e) => (e.currentTarget.style.background = '#3b82f6')}
        >
          ✏️ Edit
        </button>
        <button
          onClick={() => {
            console.log('[ContentCard] Delete clicked for content:', content.id);
            onDelete(content.id);
          }}
          style={{
            padding: '10px 16px',
            background: '#ef4444',
            color: '#fff',
            border: 'none',
            borderRadius: '6px',
            cursor: 'pointer',
            fontSize: '14px',
            fontWeight: 'bold',
            transition: 'background 0.3s',
            whiteSpace: 'nowrap',
          }}
          onMouseEnter={(e) => (e.currentTarget.style.background = '#dc2626')}
          onMouseLeave={(e) => (e.currentTarget.style.background = '#ef4444')}
        >
          ️ Delete
        </button>
      </div>
    </div>
  );
};

