// Get all children (professional/admin)
// ============================================================================
// GET /child/all
const getAllChildren = async (req, res) => {
  try {
    const children = await childModel.getAll();

    res.status(200).json({
      success: true,
      message: 'All children retrieved successfully',
      data: children,
    });
  } catch (error) {
